mapper.select:
select 
from t3_algorithm_task_results
where task_id = #{flowTaskId}
   or feature_analysis_task_id = #{flowTaskId}
order by created_at asc, id asc

select 
from t3_algorithm_task_results
where task_type = #{taskType}
  and status in ('PENDING', 'RUNNING')
order by updated_at asc, id asc
limit #{limit}

mapper.delete:
delete from t3_algorithm_task_results
where task_id = #{flowTaskId}
   or feature_analysis_task_id = #{flowTaskId}

mapper.select:
select from t3_algorithm_task_results where task_type = 'FEATURE_ANALYSIS' and status = 'SUCCESS' and result_json is not null and result_json like '%combinedDataPath%'
and business_object_id = #{bizId}
and business_object_level = #{bizLevel}
order by finished_at desc, updated_at desc, id desc limit 1

mapper.sql:
where task_type = 'PROCESS_ANOMALY_DETECT'

    and status = #{status}


    and business_object_level = #{targetType}


    and business_object_id = #{targetId}


    and created_at >= #{beginTime}


    and created_at <= #{endTime}

where task_type = 'KQC_MINING'
and status = #{status}
and ( task_id like concat('%', #{keyword}, '%') or task_name like concat('%', #{keyword}, '%') or business_object_id like concat('%', #{keyword}, '%') or business_object_name like concat('%', #{keyword}, '%') or summary_result like concat('%', #{keyword}, '%') or result_value like concat('%', #{keyword}, '%') or error_message like concat('%', #{keyword}, '%') )

where t.task_type in ('FEATURE_ANALYSIS', 'FEATURE_PROCESSING', 'EARLY_DEGRADATION_POINT_DETECT', 'KEY_PROCESS', 'FAULT_PREDICT')
and t.task_type = #{taskType}
and t.status = #{status}
and ( t.task_id like concat('%', #{keyword}, '%') or coalesce(t.feature_analysis_task_id, t.task_id) like concat('%', #{keyword}, '%') or t.task_name like concat('%', #{keyword}, '%') or t.business_object_name like concat('%', #{keyword}, '%') or t.summary_result like concat('%', #{keyword}, '%') or t.result_value like concat('%', #{keyword}, '%') or t.error_message like concat('%', #{keyword}, '%') )

mapper.select:
select count(1)
from (
    select coalesce(t.feature_analysis_task_id, t.task_id) as flow_task_id
    from t3_algorithm_task_results t

    group by coalesce(t.feature_analysis_task_id, t.task_id)
) x

mapper.sql:
where task_type = 'KEY_PROCESS'

    and status = #{status}


    and business_object_level = #{targetType}


    and business_object_id = #{targetId}


    and (
        task_id like concat('%', #{keyword}, '%')
        or business_object_name like concat('%', #{keyword}, '%')
        or summary_result like concat('%', #{keyword}, '%')
        or result_value like concat('%', #{keyword}, '%')
    )
